how to structure a voting system simulator in rust?

Here's an example of how you could structure a voting system simulator in Rust. I'll break it down into components and provide a sample implementation:

```rust
use std::collections::HashMap;

// Define the core structures
#[derive(Debug, Clone, Hash, Eq, PartialEq)]
struct Candidate {
    id: u32,
    name: String,
}

#[derive(Debug, Clone)]
struct Voter {
    id: u32,
    name: String,
    has_voted: bool,
}

#[derive(Debug)]
struct Ballot {
    voter_id: u32,
    candidate_id: u32,
}

// Main VotingSystem struct to manage the election
#[derive(Debug)]
struct VotingSystem {
    candidates: Vec<Candidate>,
    voters: Vec<Voter>,
    ballots: Vec<Ballot>,
    results: HashMap<u32, u32>, // candidate_id -> vote_count
}

impl VotingSystem {
    fn new() -> Self {
        VotingSystem {
            candidates: Vec::new(),
            voters: Vec::new(),
            ballots: Vec::new(),
            results: HashMap::new(),
        }
    }

    fn add_candidate(&mut self, name: String) {
        let id = self.candidates.len() as u32;
        self.candidates.push(Candidate { id, name });
        self.results.insert(id, 0);
    }

    fn add_voter(&mut self, name: String) {
        let id = self.voters.len() as u32;
        self.voters.push(Voter {
            id,
            name,
            has_voted: false,
        });
    }

    fn cast_vote(&mut self, voter_id: u32, candidate_id: u32) -> Result<(), String> {
        // Validate voter
        let voter = self.voters
            .iter_mut()
            .find(|v| v.id == voter_id)
            .ok_or("Voter not found")?;

        if voter.has_voted {
            return Err("Voter has already voted".to_string());
        }

        // Validate candidate
        if !self.candidates.iter().any(|c| c.id == candidate_id) {
            return Err("Invalid candidate".to_string());
        }

        // Record the vote
        voter.has_voted = true;
        self.ballots.push(Ballot {
            voter_id,
            candidate_id,
        });

        // Update results
        *self.results.entry(candidate_id).or_insert(0) += 1;

        Ok(())
    }

    fn get_winner(&self) -> Option<&Candidate> {
        self.results
            .iter()
            .max_by_key(|&(_, count)| count)
            .map(|(candidate_id, _)| {
                self.candidates
                    .iter()
                    .find(|c| c.id == *candidate_id)
                    .unwrap()
            })
    }

    fn get_results(&self) -> &HashMap<u32, u32> {
        &self.results
    }
}

// Example usage
fn main() {
    let mut voting_system = VotingSystem::new();

    // Add candidates
    voting_system.add_candidate("Alice".to_string());
    voting_system.add_candidate("Bob".to_string());
    voting_system.add_candidate("Charlie".to_string());

    // Add voters
    voting_system.add_voter("Voter 1".to_string());
    voting_system.add_voter("Voter 2".to_string());
    voting_system.add_voter("Voter 3".to_string());

    // Simulate voting
    match voting_system.cast_vote(0, 1) {
        Ok(_) => println!("Vote cast successfully"),
        Err(e) => println!("Error casting vote: {}", e),
    }

    match voting_system.cast_vote(1, 0) {
        Ok(_) => println!("Vote cast successfully"),
        Err(e) => println!("Error casting vote: {}", e),
    }

    match voting_system.cast_vote(2, 1) {
        Ok(_) => println!("Vote cast successfully"),
        Err(e) => println!("Error casting vote: {}", e),
    }

    // Display results
    println!("Results: {:?}", voting_system.get_results());

    // Display winner
    if let Some(winner) = voting_system.get_winner() {
        println!("Winner: {} with {} votes", 
            winner.name, 
            voting_system.results.get(&winner.id).unwrap()
        );
    }
}
```

